const primerItem = $input.first();
let texto = "";
if (primerItem && primerItem.json && primerItem.json.response) {
    texto = primerItem.json.response;
} else if (primerItem && primerItem.json && primerItem.json.text) {
    texto = primerItem.json.text;
}

let minuta = "No se pudo extraer el texto de la minuta";
let datos_json = {};

if (texto.includes("---MINUTA---")) {
    const partes = texto.split("---MINUTA---");
    if (partes.length > 1) {
        minuta = partes[1].split("---JSON---")[0].trim();
    }
} else {
    minuta = texto.split("{")[0].trim();
}

try {
    let raw_json_part = "";
    if (texto.includes("```json")) {
        raw_json_part = texto.split("```json")[1].split("```")[0];
    } else if (texto.includes("---JSON---")) {
        raw_json_part = texto.split("---JSON---")[1];
    } else {
        const firstBrace = texto.indexOf("{");
        const lastBrace = texto.lastIndexOf("}");
        if (firstBrace !== -1 && lastBrace !== -1) {
            raw_json_part = texto.substring(firstBrace, lastBrace + 1);
        }
    }
    raw_json_part = raw_json_part.trim().replace(/[\x00-\x1F\x7F-\x9F]/g, "");
    datos_json = JSON.parse(raw_json_part);
} catch (e) {
    datos_json = { 
        error: "JSON mal formado por la IA", 
        original_text_snippet: texto.substring(0, 50) + "..." 
    };
}

return [{
    json: {
        minuta: minuta,
        json: datos_json,
        raw_llm_response: texto
    }
}];
